import React from 'react'
import Preloader from '../helper/Preloader'
import HeaderOne from '../components/HeaderOne'
import Breadcrumb from '../components/Breadcrumb'
import AllHealthPackages from '../components/AllHealthPackages'
import FooterOne from '../components/FooterOne'
import { SEO } from '../utils/SEO'

const HealthPackages = () => {
  return (
    <>
     <SEO
        title="4ceps | Healthcare Packages & Health Checkup Plans – Book Online"
        description="Explore comprehensive healthcare packages and preventive checkup plans on 4ceps.choose & book today for health screening, diagnostics & wellness tests."
        url="https://4ceps.com/all-package"
      />
    <Preloader/>
    <HeaderOne/>
    <Breadcrumb/>
    <AllHealthPackages/>
    <FooterOne/>
    </>
  )
}

export default HealthPackages